export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:42 變成了 19:00。19:00 變成了 19:30。19:30 變成了 20:00。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保健老師沒有回來。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她有回來過一次。大約 19:10 左右，顧言聽見走廊上的腳步聲，門被推開一條縫，保健老師的半張臉出現在縫隙裡。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "禮堂那邊又暈了一個，我還得待一會兒。你自己沒問題吧？", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "好。有不舒服打內線。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門又關上了。腳步聲又遠了。南翼又安靜了。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她回來看了一眼。只是看了一眼。然後又走了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她不是故意的。禮堂真的有學生暈倒。百年校慶、颱風天、室內擁擠、空氣悶——暈倒太正常了。她被流程叫走了。她在做她的工作。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但結果是：我在這裡。她不在這裡。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:00。他在內間裡開始走動。從裡面的病床到門口，七步。從門口到窗邊，五步。從窗邊到後門，四步。這個房間的尺寸他已經用腳步量過很多遍了。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十六步。走完一圈十六步。外間加走廊門到這裡。如果保健老師不在，正門出去需要穿過外間，經過她的空桌子，推開走廊門。走廊門沒有鎖。但走廊上沒有人。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)後門。防颱期間勿開。我不知道鎖是什麼類型。壓把鎖，老式。外面是設備平台。我不知道平台上現在有什麼。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)窗戶。磨砂玻璃。防颱膠帶。外面半高防颱板。上方通風百葉。塑膠布。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三個方向。三個出口。一個需要穿過空無一人的走廊，一個被防颱規定封著，一個被封在膠帶和板子後面。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一個單獨看都合理。走廊本來就人少。後門本來就不應該開。窗戶本來就應該防颱。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但三個加在一起——", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到窗邊，停住。窗外的世界已經完全黑了。磨砂玻璃變成一面灰黑色的板，防颱膠帶在日光燈的反射下顯得格外清晰。他能看見自己的臉映在玻璃上，模糊的，像一個不太確定的影子。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨聲比剛才更大了。不是細密的雨，是那種密集的、沉重的、像有人在屋頂倒水的暴雨。打在防颱板上咚咚咚咚，節奏快到分不清單獨的敲擊。風從某個角度灌過來的時候，整面外牆都在承受壓力，他甚至能感覺到腳下的地板有非常微弱的震動。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)雨變大了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)從下午到現在，雨一直在變大。早上是細雨。中午是中雨。下午是大雨。現在——暴雨。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這是真實的。颱風正在接近。氣象預報說了。邵叔也說了。學校才會取消戶外活動。這一切都是真的。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但——", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低下頭，看了看手機。20:03。訊號——一格。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一格。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)下午的時候是三格。現在剩一格。颱風影響訊號，正常。南翼在建築內側，本來訊號就不好。正常。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但如果只剩一格，訊息就發不出去。電話也可能打不通。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他打開通訊錄，找到邵叔的號碼。按下去。聽筒裡傳來嘟——嘟——嘟——然後斷了。不是忙線，是訊號中斷的那種突兀的安靜。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯打不通。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊號問題。颱風。正常。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)正常。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機放回口袋。在房間裡又走了一圈。十六步。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我來整理一下。從18:00到現在，發生了什麼。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一：山路管制，校務車停了。這是好事。這代表邵叔真的在封死亡路線。18:30，我活過了第二輪的死亡時間。這一點是真的。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二：保健老師被調走。校安被調走。南翼空了。走廊上沒有人了。這些調動都有合理原因。但結果是——我身邊沒有人了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三：雨變大了。風壓變大了。窗戶在震。通風口的塑膠布貼死了。手機訊號剩一格。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第四：我打不通邵叔的電話。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我深吸了一口。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "空氣——沒有味道。但比下午悶了。說不上來哪裡不對。也許是因為空調停了——對，空調什麼時候停的？他想不起來。也許是 19:00 左右。也許更早。外面開了備用電，但南翼這一區的空調沒有恢復。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)空氣悶。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)因為通風口被塑膠布擋著。因為窗戶被防颱板和膠帶封著。因為門關著。因為空調停了。每一個原因單獨看都合理。合在一起——空氣就開始變悶了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走回床邊，坐下。床墊的硬度沒有變。枕頭的薄度沒有變。日光燈的白色沒有變。變的是房間外面。走廊的腳步聲，從一小時前開始，就再也沒有出現過了。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)校安的巡邏頻率變了。下午的時候，每隔十五到二十分鐘，走廊上會有校安走過。不會停，但會經過。19:00 之後，巡邏變稀了。19:30 之後，完全沒有了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們都被調走了。禮堂、體育館、主樓——所有室內活動都在那邊。南翼本來就不是活動區域。加上颱風加劇——巡邏優先順序自然就往人多的地方傾斜。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)正常。一切正常。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——但「正常」正在一點一點地把這個房間變成一座孤島。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:15。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我從13:30進來。到現在，快七個小時了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)七個小時裡，這個房間發生了什麼變化？", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)保健老師從在場到短暫離開到幾乎不在。校安巡邏從固定頻率到稀疏到消失。走廊從有人到安靜到死寂。手機訊號從三格到一格。空氣從正常到悶。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)窗戶——防颱膠帶比下午的時候看起來更擋光了。不是因為膠帶變了，是因為外面更黑了。雨更大了。風壓更重了。外面的世界正在一點一點被暴雨和黑暗吃掉，而這些膠帶和板子正在把我和那個世界隔開。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我開始覺得——", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。又走了一圈。十六步。經過窗邊的時候，他停了一下，看了一眼通風百葉。塑膠布仍然緊貼在上面。嗡嗡的聲音持續不斷。風的節奏和雨的節奏混在一起，分不開了。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)想一想。我從三個循環裡學到了什麼。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪。我把訊息完整交給邵叔。他知道了所有內容。當晚我死在鐘樓。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二輪。我不找邵叔。我避開鐘樓。我逃出學校。我死在後山。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三輪。我只透露部分訊息。我讓邵叔用權限封鐘樓、停車輛。他照做了。前兩輪的死亡路線全部被堵住。我活過了18:30。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但現在——我被放在一個越來越安靜、越來越空、越來越悶的房間裡。手機打不通。走廊上沒有人。窗戶被封著。後門被鎖著。空調停了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一個讓這個房間變成現在這個樣子的因素，都來自同一個地方。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)把我安排進南翼醫務室——來自邵叔。保健老師被調走——來自指揮室。校安巡邏變稀——來自指揮室。空調停電——南翼局部電力管理。防颱膠帶和板子——防颱流程。後門鎖著——防颱規定。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一條都指向同一個源頭：今天的安全安排。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天的安全安排——全部出自指揮室。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)指揮室——", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在房間正中間。不動了。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我在最安全的房間裡。這個房間是今天最有權限的大人替我選的。值班老師在。巡邏校安在。離指揮區近。南翼人少。每一個理由都合理。每一個安排都恰當。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但保健老師被調走了。校安被調走了。走廊空了。手機打不通了。窗戶被封了。後門鎖了。空氣在變悶。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果這是一個陷阱——它不需要有人拿刀站在門口。它只需要每一個正常的人都去做正常的事，每一個正常的流程都往同一個方向走，每一個正常的理由都讓這個房間更封閉一點點。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一點點。一點點。像在砌牆。一塊磚、一塊磚地，把這個房間變成——", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要嚇自己。邵叔真的封了鐘樓。他真的停了校務車。我真的活過了18:30。這些都是真的。他的保護是真的。他的權限是真的。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但他的保護，同時也是——把我放進了這個房間。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他讓我相信這裡安全。然後所有讓這裡安全的人，一個一個被調走了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我不知道。我真的不知道。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我只知道一件事：我不喜歡這個感覺。這個房間的牆壁沒有變。門沒有變。窗沒有變。但感覺——像是在收縮。像有什麼東西正從四面八方，很慢、很安靜、很合理地，圍攏過來。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:22。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在心裡又走了一遍今天的時間線。早上醒來。查車輛表。找邵叔。邵叔調流程。鐘樓封了。校史館封了。我被帶到醫務室。保健老師值班。校安巡邏。氣象升級。校務車停了。山路封了。18:30。活過了。保健老師被叫走。校安被調走。走廊空了。手機打不通。空氣變悶。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一環都扣著下一環。像齒輪。像設計好的。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果是設計好的——那設計者不需要在現場。他只需要站在最開始的那個點，把第一塊骨牌推倒。後面的每一塊，都會自己倒下去。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一塊骨牌是什麼？", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——是「你先待在這裡」。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔說的。「你不是犯人，是需要保護的人。先待在這裡。」", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:25。雨更大了。窗框的震動從偶爾變成持續。通風百葉的嗡嗡聲變成了一種低頻的壓迫。日光燈的白光照在床單上、牆壁上、他的手上，什麼都照得很清楚，但光線本身也開始讓他覺得不對勁——太白了。太均勻了。像手術燈。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我還在等。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我在等保健老師回來。等校安走過走廊。等邵叔打電話來說監控有結果了。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但20:30了。沒有人回來。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他坐在床上。兩手放在膝蓋上。手機訊號一格。房間十六步。窗外暴雨。通風口嗡嗡。日光燈白得刺眼。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所有的安全安排都來自指揮室。所有的流程調度都來自指揮室。所有的門禁和封鎖都來自指揮室。我現在最需要的人——保健老師、校安、邵叔——全都在別的地方。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而我在這裡。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)在最安全的房間裡。在最合理的安排下。在最專業的保護中。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯我甩不掉那個感覺。", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這個房間是一個籠子。不是突然被關上的那種。是一根欄杆、一根欄杆，慢慢、慢慢、合理地，被插進來的那種。每一根欄杆都有正當理由。每一根欄杆都是為了我的安全。但所有欄杆插完之後——", background: Background.Chapter_3_Ch3_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有把那句話想完。", background: Background.Chapter_3_Ch3_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:28。他繼續等。", background: Background.Chapter_3_Ch3_Act12_S0 },
];
